"use client";

import React, { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { Download, Search, Filter, Mail, Phone, Calendar, User, GraduationCap, Loader2, X, Trash2 } from 'lucide-react';
import ExcelJS from 'exceljs';
import { COLLEGE_LOGO_BASE64 } from '@/lib/logo-base64';

interface Inquiry {
  id: string;
  name: string;
  father_name?: string;
  email: string;
  phone: string;
  course: string;
  status: string;
  message: string;
  created_at: string;
}

export default function AdmissionsAdmin() {
  const [inquiries, setInquiries] = useState<Inquiry[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedInquiry, setSelectedInquiry] = useState<Inquiry | null>(null);
  const [isUpdating, setIsUpdating] = useState<string | null>(null);
  const [isDeleting, setIsDeleting] = useState<string | null>(null);

  async function fetchInquiries(searchQuery: string = '') {
    setIsLoading(true);
    try {

      let query = supabase
        .from('inquiries')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(100);
        
      if (searchQuery) {
        query = query.or(`name.ilike.%${searchQuery}%,course.ilike.%${searchQuery}%,father_name.ilike.%${searchQuery}%`);
      }
      
      const { data, error } = await query;
      
      if (error) {
        console.error('Supabase query error:', error);
        return;
      }

      if (data) {
        setInquiries(data);
      }
    } catch (err: any) {
      console.error('Failed to fetch inquiries:', err);
    } finally {
      setIsLoading(false);
    }
  }

  async function updateStatus(id: string, newStatus: string) {
    setIsUpdating(id);
    try {
      const { error } = await supabase
        .from('inquiries')
        .update({ status: newStatus })
        .eq('id', id);
      
      if (error) throw error;
      
      setInquiries(prev => prev.map(inq => inq.id === id ? { ...inq, status: newStatus } : inq));
      if (selectedInquiry?.id === id) {
        setSelectedInquiry(prev => prev ? { ...prev, status: newStatus } : null);
      }
    } catch (err: any) {
      alert(`Failed to update status: ${err.message}`);
    } finally {
      setIsUpdating(null);
    }
  }

  async function deleteInquiry(id: string) {
    if (!confirm('Are you sure you want to delete this inquiry?')) return;
    
    setIsDeleting(id);
    try {
      console.log('Attempting to delete inquiry:', id);
      
      const { error, data, count } = await supabase
        .from('inquiries')
        .delete({ count: 'exact' })
        .eq('id', id)
        .select();
      
      if (error) {
        console.error('Delete error from Supabase:', error);
        throw error;
      }
      
      if (count === 0) {
        alert('Database reported 0 rows deleted. The record may have already been removed, or your account lacks permission to delete it. Please check RLS policies.');
        return;
      }
      
      console.log(`Delete successful, ${count} rows affected. data:`, data);
      
      // Update local state
      setInquiries(prev => prev.filter(inq => inq.id !== id));
      setSelectedInquiry(null);
      
      // Force a silent refresh of the data from the server to ensure synchronization
      await fetchInquiries(searchTerm);
      
    } catch (err: any) {
      console.error('Final Delete catch:', err);
      alert(`Delete failed: ${err.message || 'Unknown error'}`);
    } finally {
      setIsDeleting(null);
    }
  }

  useEffect(() => {
    const delayDebounceFn = setTimeout(() => {
      fetchInquiries(searchTerm);
    }, 500);

    return () => clearTimeout(delayDebounceFn);
  }, [searchTerm]);

  const exportToExcel = async () => {
    // ΓöÇΓöÇ Color Palette ΓöÇΓöÇ
    const DARK_GREEN  = "1B5E20";
    const MED_GREEN   = "2E7D32";
    const LIGHT_GREEN = "E8F5E9";
    const HDR_GREEN   = "388E3C";
    const GOLD        = "F9A825";
    const ROW_ALT     = "F1F8E9";
    const GREY_HEX    = "757575";

    const thinBorder: Partial<ExcelJS.Borders> = {
      top:    { style: "thin", color: { argb: "FFCCCCCC" } },
      bottom: { style: "thin", color: { argb: "FFCCCCCC" } },
      left:   { style: "thin", color: { argb: "FFCCCCCC" } },
      right:  { style: "thin", color: { argb: "FFCCCCCC" } },
    };

    const hdrBorder: Partial<ExcelJS.Borders> = {
      top:    { style: "thin", color: { argb: "FF" + MED_GREEN } },
      bottom: { style: "thin", color: { argb: "FF" + MED_GREEN } },
      left:   { style: "thin", color: { argb: "FF" + MED_GREEN } },
      right:  { style: "thin", color: { argb: "FF" + MED_GREEN } },
    };

    // ΓöÇΓöÇ Prepare Data ΓöÇΓöÇ
    const headers = ["S.No", "Student Name", "Father's Name", "Email", "Phone", "Course Applied", "Group", "Status", "Applied Date", "Address"];
    const totalCols = headers.length; // 10

    const dataRows = inquiries.map((inq, i) => [
      i + 1,
      inq.name,
      inq.father_name || "N/A",
      inq.email,
      inq.phone,
      inq.course,
      inq.message.split("|")[0].replace("Group: ", "").trim(),
      inq.status || "New",
      new Date(inq.created_at).toLocaleDateString("en-IN", { day: "2-digit", month: "2-digit", year: "numeric" }),
      inq.message.split("|")[1]?.replace("Address: ", "").trim() || "N/A",
    ]);

    const now = new Date();
    const dateStr = now.toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" }) + " | " + now.toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit", hour12: true });

    // ΓöÇΓöÇ Create Workbook ΓöÇΓöÇ
    const wb = new ExcelJS.Workbook();
    const ws = wb.addWorksheet("Admission Report", {
      pageSetup: { orientation: "landscape", fitToPage: true, fitToWidth: 1, fitToHeight: 0 },
    });

    // ΓöÇΓöÇ Column Widths ΓöÇΓöÇ
    const colWidths = [5, 22, 20, 28, 14, 30, 12, 12, 22, 40];
    ws.columns = colWidths.map(w => ({ width: w }));

    // ΓöÇΓöÇ Helper: fill every cell in a row ΓöÇΓöÇ
    const fillRow = (rowNum: number, fill: ExcelJS.Fill, font: Partial<ExcelJS.Font>, alignment?: Partial<ExcelJS.Alignment>) => {
      const row = ws.getRow(rowNum);
      for (let c = 1; c <= totalCols; c++) {
        const cell = row.getCell(c);
        cell.fill = fill;
        cell.font = font as ExcelJS.Font;
        if (alignment) cell.alignment = alignment as ExcelJS.Alignment;
      }
    };

    const solidFill = (color: string): ExcelJS.Fill => ({
      type: "pattern", pattern: "solid", fgColor: { argb: "FF" + color },
    });

    // ΓöÇΓöÇ ROW 1: Logo + College Name ΓöÇΓöÇ
    ws.getRow(1).height = 55;
    ws.mergeCells("A1:J1");
    fillRow(1, solidFill(DARK_GREEN),
      { name: "Arial", size: 20, bold: true, color: { argb: "FFFFFFFF" } },
      { horizontal: "center", vertical: "middle" }
    );
    ws.getCell("A1").value = "S.K. DEGREE COLLEGE & PG COLLEGE";

    // Insert logo image at column D (index 3)
    const logoId = wb.addImage({ base64: COLLEGE_LOGO_BASE64, extension: "jpeg" });
    ws.addImage(logoId, {
      tl: { col: 3, row: 0 },
      ext: { width: 70, height: 50 },
    });

    // ΓöÇΓöÇ ROW 2: Affiliation ΓöÇΓöÇ
    ws.getRow(2).height = 22;
    ws.mergeCells("A2:J2");
    fillRow(2, solidFill(MED_GREEN),
      { name: "Arial", size: 12, bold: true, color: { argb: "FFFFFFFF" } },
      { horizontal: "center", vertical: "middle" }
    );
    ws.getCell("A2").value = "Affiliated to Andhra University | Established in 2005";

    // ΓöÇΓöÇ ROW 3: Contact (Address row removed) ΓöÇΓöÇ
    ws.getRow(3).height = 16;
    ws.mergeCells("A3:J3");
    ws.getCell("A3").value = "Ph: 94412 53163 | Email: arunodayaes@yahoo.com | www.skdegreecollege.com";
    ws.getCell("A3").font = { name: "Arial", size: 9, italic: true, color: { argb: "FF" + GREY_HEX } };
    ws.getCell("A3").alignment = { horizontal: "center", vertical: "middle" };

    // ΓöÇΓöÇ ROW 4: Gold divider ΓöÇΓöÇ
    ws.getRow(4).height = 8;
    ws.mergeCells("A4:J4");
    fillRow(4, solidFill(GOLD), {}, {});

    // ΓöÇΓöÇ ROW 5: Report title ΓöÇΓöÇ
    ws.getRow(5).height = 24;
    ws.mergeCells("A5:J5");
    fillRow(5, solidFill(LIGHT_GREEN),
      { name: "Arial", size: 13, bold: true, color: { argb: "FF" + DARK_GREEN } },
      { horizontal: "center", vertical: "middle" }
    );
    ws.getCell("A5").value = "ONLINE APPLICATION LIST \u2013 ADMISSIONS 2026-27";

    // ΓöÇΓöÇ ROW 6: Date/Time ΓöÇΓöÇ
    ws.getRow(6).height = 16;
    ws.mergeCells("A6:J6");
    ws.getCell("A6").value = `Date of Printing: ${dateStr}`;
    ws.getCell("A6").font = { name: "Arial", size: 9, italic: true, color: { argb: "FF" + GREY_HEX } };
    ws.getCell("A6").alignment = { horizontal: "right", vertical: "middle" };

    // ΓöÇΓöÇ ROW 7: Column Headers ΓöÇΓöÇ
    ws.getRow(7).height = 30;
    const headerRow = ws.getRow(7);
    headers.forEach((h, i) => {
      const cell = headerRow.getCell(i + 1);
      cell.value = h;
      cell.fill = solidFill(HDR_GREEN);
      cell.font = { name: "Arial", size: 10, bold: true, color: { argb: "FFFFFFFF" } };
      cell.alignment = { horizontal: "center", vertical: "middle" };
      cell.border = hdrBorder;
    });

    // ΓöÇΓöÇ DATA ROWS ΓöÇΓöÇ
    const STATUS_COLORS: Record<string, { bg: string; fg: string }> = {
      "New":       { bg: "E3F2FD", fg: "1565C0" },
      "Contacted": { bg: "FFF3E0", fg: "E65100" },
      "Confirmed": { bg: "E8F5E9", fg: "2E7D32" },
      "Processed": { bg: "E8F5E9", fg: "2E7D32" },
      "Rejected":  { bg: "FFEBEE", fg: "C62828" },
    };

    dataRows.forEach((rowData, idx) => {
      const rowNum = 8 + idx;
      const row = ws.getRow(rowNum);
      row.height = 20;
      const isEven = idx % 2 === 1;

      rowData.forEach((val, colIdx) => {
        const cell = row.getCell(colIdx + 1);
        cell.value = val;
        cell.font = { name: "Arial", size: 9 };
        cell.alignment = { vertical: "middle", wrapText: colIdx === 9 };
        cell.border = thinBorder;

        if (isEven) {
          cell.fill = solidFill(ROW_ALT);
        }

        // Status badge (column index 7)
        if (colIdx === 7) {
          const sc = STATUS_COLORS[String(val)];
          if (sc) {
            cell.fill = solidFill(sc.bg);
            cell.font = { name: "Arial", size: 9, bold: true, color: { argb: "FF" + sc.fg } };
            cell.alignment = { horizontal: "center", vertical: "middle" };
          }
        }
      });
    });

    // ΓöÇΓöÇ SUMMARY ROW ΓöÇΓöÇ
    const summaryRowNum = 8 + dataRows.length;
    ws.mergeCells(`A${summaryRowNum}:J${summaryRowNum}`);
    ws.getRow(summaryRowNum).height = 25;
    fillRow(summaryRowNum, solidFill(DARK_GREEN),
      { name: "Arial", size: 10, bold: true, color: { argb: "FFFFFFFF" } },
      { horizontal: "center", vertical: "middle" }
    );
    ws.getCell(`A${summaryRowNum}`).value = `Total Applications Received: ${dataRows.length}`;

    // ΓöÇΓöÇ FOOTER ROW ΓöÇΓöÇ
    const footerRowNum = summaryRowNum + 2;
    ws.mergeCells(`A${footerRowNum}:J${footerRowNum}`);
    ws.getCell(`A${footerRowNum}`).value = "This is a computer-generated report from the S.K. Degree College online admission portal. For queries, contact the college administration.";
    ws.getCell(`A${footerRowNum}`).font = { name: "Arial", size: 8, italic: true, color: { argb: "FF" + GREY_HEX } };
    ws.getCell(`A${footerRowNum}`).alignment = { horizontal: "center", vertical: "middle" };

    // ΓöÇΓöÇ FREEZE PANES ΓöÇΓöÇ
    ws.views = [{ state: "frozen", ySplit: 7 }];

    // ΓöÇΓöÇ PRINT TITLE ROWS ΓöÇΓöÇ
    ws.pageSetup.printTitlesRow = "1:7";

    // ΓöÇΓöÇ DOWNLOAD ΓöÇΓöÇ
    const buffer = await wb.xlsx.writeBuffer();
    const blob = new Blob([buffer], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `SK_College_Admission_Report_${now.getFullYear()}.xlsx`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const [activeTab, setActiveTab] = useState<'Admissions' | 'Contact'>('Admissions');

  const admissionsCount = inquiries.filter(inq => inq.course !== 'Contact Inquiry').length;
  const contactCount = inquiries.filter(inq => inq.course === 'Contact Inquiry').length;

  const filteredInquiries = inquiries.filter(inq => {
    if (activeTab === 'Admissions') return inq.course !== 'Contact Inquiry';
    if (activeTab === 'Contact') return inq.course === 'Contact Inquiry';
    return false;
  });

  return (
    <div className="space-y-8 relative">
      {/* Header Actions */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h1 className="text-3xl font-black text-academic-navy tracking-tight">Student Inquiries</h1>
          </div>
          <p className="text-slate-500 font-medium">Manage applications and contact messages.</p>
        </div>
        <div className="flex gap-2">
           <button 
             onClick={exportToExcel}
             className="flex items-center justify-center gap-2 px-6 py-3 bg-white border border-slate-200 text-academic-navy font-black rounded-xl hover:bg-slate-50 transition-all active:opacity-80 active:translate-y-[1px]"
           >
             <Download size={20} />
             Export
           </button>
           <button 
             onClick={() => fetchInquiries(searchTerm)}
             className="flex items-center justify-center gap-2 px-6 py-3 bg-academic-gold text-academic-navy font-black rounded-xl hover:shadow-xl hover:shadow-academic-gold/20 transition-all active:opacity-80 active:translate-y-[1px]"
           >
             <Loader2 className={isLoading ? 'animate-spin' : ''} size={20} />
             Refresh
           </button>
        </div>
      </div>

      {/* Tabs & Search */}
      <div className="flex flex-col md:flex-row gap-4">
        <div className="flex bg-slate-100 p-1.5 rounded-2xl md:w-fit">
          {(['Admissions', 'Contact'] as const).map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`
                px-6 py-2.5 rounded-xl text-[13px] font-black uppercase tracking-widest transition-all flex items-center gap-2
                ${activeTab === tab 
                  ? 'bg-white text-academic-navy shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
                }
              `}
            >
              {tab === 'Admissions' ? 'Applications' : 'Messages'}
              <span className={`
                px-2 py-0.5 rounded-full text-[11px]
                ${activeTab === tab ? 'bg-academic-navy text-white' : 'bg-slate-200 text-slate-500'}
              `}>
                {tab === 'Admissions' ? admissionsCount : contactCount}
              </span>
            </button>
          ))}
        </div>
        <div className="relative flex-1">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text"
            placeholder="Search by student name or course..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-12 pr-12 py-3.5 bg-white border border-slate-100 rounded-2xl focus:border-academic-gold outline-none shadow-sm transition-all font-medium"
          />
          {searchTerm && (
            <button 
              onClick={() => setSearchTerm('')}
              className="absolute right-4 top-1/2 -translate-y-1/2 p-1 hover:bg-slate-100 rounded-full transition-colors text-slate-400 hover:text-academic-navy"
            >
              <X size={16} />
            </button>
          )}
        </div>
      </div>

      {/* Data View */}
      <div className="bg-white rounded-[2.5rem] shadow-xl border border-slate-100 overflow-hidden min-h-[400px]">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center h-64 text-slate-400">
            <Loader2 className="animate-spin mb-4" size={40} />
            <p className="font-bold">Loading inquiries...</p>
          </div>
        ) : (
          <>
            {/* Desktop Table */}
            <div className="hidden lg:block overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50/50 border-b border-slate-100">
                    <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Student</th>
                    <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Contact</th>
                    <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Course/Inquiry</th>
                    <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                    <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredInquiries.map((inq) => (
                    <tr key={inq.id} className="hover:bg-slate-50/30 transition-colors group">
                      <td className="px-8 py-5">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 rounded-full bg-academic-navy/5 flex items-center justify-center text-academic-navy font-bold">
                            {inq.name[0]}
                          </div>
                          <span className="font-black text-academic-navy">{inq.name}</span>
                        </div>
                      </td>
                      <td className="px-8 py-5">
                        <div className="space-y-1">
                          <div className="flex items-center gap-2 text-sm text-slate-600 font-bold">
                            <Mail size={14} className="text-academic-gold" />
                            {inq.email}
                          </div>
                          <div className="flex items-center gap-2 text-sm text-slate-500 font-bold">
                            <Phone size={14} className="text-academic-gold" />
                            {inq.phone}
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-5">
                        <span className="px-3 py-1 bg-blue-50 text-blue-700 rounded-lg text-[10px] font-black uppercase tracking-wider">
                          {inq.course}
                        </span>
                      </td>
                      <td className="px-8 py-5">
                        <span className={`
                          px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider
                          ${inq.status === 'Processed' ? 'bg-green-50 text-green-700' : 
                            inq.status === 'Contacted' ? 'bg-orange-50 text-orange-700' : 'bg-slate-100 text-slate-600'}
                        `}>
                          {inq.status || 'New'}
                        </span>
                      </td>
                      <td className="px-8 py-5 text-right">
                        <button 
                          onClick={() => setSelectedInquiry(inq)}
                          className="px-4 py-2 bg-slate-100 text-academic-navy font-black rounded-xl hover:bg-academic-navy hover:text-white transition-all text-[13px] uppercase tracking-widest active:opacity-80 active:translate-y-[1px]"
                        >
                          Details
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Mobile Cards */}
            <div className="lg:hidden divide-y divide-slate-100">
              {filteredInquiries.map((inq) => (
                <div key={inq.id} className="p-6 space-y-4 hover:bg-slate-50/30 transition-all">
                  <div className="flex justify-between items-start">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-academic-navy/5 flex items-center justify-center text-academic-navy font-bold">
                        {inq.name[0]}
                      </div>
                      <div>
                        <h3 className="font-black text-academic-navy">{inq.name}</h3>
                        <p className="text-xs text-slate-400 font-bold uppercase">{inq.status || 'New'}</p>
                      </div>
                    </div>
                    <button 
                      onClick={() => setSelectedInquiry(inq)}
                      className="p-2 bg-slate-100 rounded-xl text-academic-navy active:opacity-80 active:translate-y-[1px]"
                    >
                      <Filter size={18} />
                    </button>
                  </div>
                  <div className="flex items-center gap-4 text-xs font-bold text-slate-500">
                    <span className="flex items-center gap-1.5"><Mail size={12}/> {inq.email}</span>
                    <span className="flex items-center gap-1.5"><GraduationCap size={12}/> {inq.course}</span>
                  </div>
                </div>
              ))}
            </div>
          </>
        )}

        {!isLoading && filteredInquiries.length === 0 && (
          <div className="p-12 text-center">
            <User className="mx-auto mb-4 text-slate-200" size={48} />
            <p className="text-slate-400 font-medium">No inquiries found matching your search.</p>
          </div>
        )}
      </div>

      {/* Detail Modal */}
      {selectedInquiry && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-academic-navy/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
              <div className="bg-academic-navy p-8 text-white flex justify-between items-start">
                 <div className="flex items-center gap-4">
                    <div className="w-16 h-16 rounded-2xl bg-academic-gold/20 border border-academic-gold/30 flex items-center justify-center text-academic-gold text-2xl font-black">
                       {selectedInquiry.name ? selectedInquiry.name[0] : '?'}
                    </div>
                    <div>
                       <h2 className="text-2xl font-black tracking-tight">{selectedInquiry.name}</h2>
                       <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Application Details</p>
                    </div>
                 </div>
                 <button onClick={() => setSelectedInquiry(null)} className="p-2 hover:bg-white/10 rounded-full transition-colors active:opacity-80">
                    <X size={24} />
                 </button>
              </div>

              <div className="p-8 space-y-8">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-4">
                       <div>
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Contact Details</p>
                          <div className="space-y-2">
                             <div className="flex items-center gap-3 text-slate-600 font-bold">
                                <Mail size={16} className="text-academic-gold" />
                                {selectedInquiry.email}
                             </div>
                             <div className="flex items-center gap-3 text-slate-600 font-bold">
                                <Phone size={16} className="text-academic-gold" />
                                {selectedInquiry.phone}
                             </div>
                          </div>
                       </div>
                        <div>
                           <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Father&apos;s Name</p>
                           <div className="flex items-center gap-3 text-slate-600 font-bold">
                              <User size={16} className="text-academic-gold" />
                              {selectedInquiry.father_name || 'Not Provided'}
                           </div>
                        </div>
                       <div>
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Interested Course</p>
                          <div className="inline-flex items-center gap-2 px-4 py-2 bg-blue-50 text-blue-700 rounded-xl font-black text-sm uppercase">
                             <GraduationCap size={16} />
                             {selectedInquiry.course}
                          </div>
                       </div>
                    </div>
                    
                    <div className="space-y-4">
                       <div>
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Submission Date</p>
                          <div className="flex items-center gap-3 text-slate-600 font-bold">
                             <Calendar size={16} className="text-academic-gold" />
                             {new Date(selectedInquiry.created_at).toLocaleString()}
                          </div>
                       </div>
                       <div>
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Status</p>
                          <div className="flex items-center gap-2">
                             <select 
                                value={selectedInquiry.status || 'New'} 
                                onChange={(e) => updateStatus(selectedInquiry.id, e.target.value)}
                                disabled={isUpdating === selectedInquiry.id}
                                className="px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl font-bold text-sm outline-none focus:border-academic-gold"
                             >
                                <option value="New">New Application</option>
                                <option value="Contacted">Contacted</option>
                                <option value="Processed">Processed</option>
                                <option value="Rejected">Rejected</option>
                             </select>
                             {isUpdating === selectedInquiry.id && <Loader2 size={16} className="animate-spin text-academic-gold" />}
                          </div>
                       </div>
                    </div>
                 </div>

                 <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Additional Information (Group & Address)</p>
                    <p className="text-slate-700 font-medium whitespace-pre-wrap leading-relaxed">
                       {selectedInquiry.message || 'No additional details provided.'}
                    </p>
                 </div>

                 <div className="flex gap-4">
                    <button 
                       onClick={() => deleteInquiry(selectedInquiry.id)}
                       disabled={isDeleting === selectedInquiry.id}
                       className="px-6 py-4 bg-red-50 text-red-600 font-black rounded-2xl border border-red-100 hover:bg-red-100 transition-all flex items-center gap-2 disabled:opacity-50 active:opacity-80 active:translate-y-[1px]"
                    >
                       {isDeleting === selectedInquiry.id ? <Loader2 size={20} className="animate-spin" /> : <Trash2 size={20} />}
                       {isDeleting === selectedInquiry.id ? 'Deleting...' : 'Delete Inquiry'}
                    </button>
                    <button 
                       onClick={() => setSelectedInquiry(null)}
                       className="flex-1 py-4 bg-academic-navy text-white font-black rounded-2xl hover:bg-slate-800 transition-all shadow-xl shadow-academic-navy/20 active:opacity-80 active:translate-y-[1px]"
                    >
                       Close Details
                    </button>
                 </div>
               </div>
            </div>
         </div>
      )}
    </div>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { 
  Users, 
  GraduationCap, 
  Bell, 
  TrendingUp, 
  Clock, 
  ArrowUpRight,
  ShieldCheck,
  Globe,
  Loader2
} from 'lucide-react';
import Link from 'next/link';

export default function AdminOverview() {
  const [stats, setStats] = useState({
    inquiries: 0,
    notices: 0,
    faculty: 0,
  });
  interface Inquiry {
    id: string;
    name: string;
    course: string;
    created_at: string;
  }

  const [recentInquiries, setRecentInquiries] = useState<Inquiry[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchDashboardData() {
      try {
        // Fetch counts
        const [inqRes, notRes, facRes] = await Promise.all([
          supabase.from('inquiries').select('id', { count: 'exact', head: true }),
          supabase.from('notices').select('id', { count: 'exact', head: true }),
          supabase.from('faculty').select('id', { count: 'exact', head: true })
        ]);

        // Fetch recent inquiries
        const { data: recentInq } = await supabase
          .from('inquiries')
          .select('id, name, course, created_at')
          .order('created_at', { ascending: false })
          .limit(3);

        setStats({
          inquiries: inqRes.count || 0,
          notices: notRes.count || 0,
          faculty: facRes.count || 0,
        });

        if (recentInq) {
          setRecentInquiries(recentInq);
        }
      } catch (err) {
        console.error('Error fetching dashboard stats:', err);
      } finally {
        setLoading(false);
      }
    }
    fetchDashboardData();
  }, []);

  const statCards = [
    { name: 'Total Inquiries', value: stats.inquiries, icon: GraduationCap, color: 'text-blue-500', bg: 'bg-blue-500/10', trend: 'Live Data' },
    { name: 'Active Notices', value: stats.notices, icon: Bell, color: 'text-amber-500', bg: 'bg-amber-500/10', trend: 'Live Data' },
    { name: 'Faculty Members', value: stats.faculty, icon: Users, color: 'text-emerald-500', bg: 'bg-emerald-500/10', trend: 'Live Data' },
  ];

  if (loading) {
    return (
      <div className="flex h-64 items-center justify-center">
        <Loader2 className="animate-spin text-blue-500" size={32} />
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Welcome Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-gradient-to-br from-blue-500/5 to-purple-500/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 pointer-events-none" />
        <div className="relative z-10">
          <h1 className="text-3xl md:text-4xl font-black text-academic-navy tracking-tight mb-2">System Overview</h1>
          <p className="text-slate-500 font-medium">Welcome back. Here&apos;s your mission control for S.K. College today.</p>
        </div>
        <div className="flex items-center gap-4 bg-emerald-50/50 p-3 rounded-2xl border border-emerald-100/50 shadow-sm relative z-10 backdrop-blur-sm">
           <div className="w-12 h-12 rounded-xl bg-emerald-100 flex items-center justify-center text-emerald-600 shadow-inner">
              <ShieldCheck size={24} />
           </div>
           <div className="pr-4">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Database Sync</p>
              <p className="text-sm font-black text-emerald-700 uppercase">Live Connected</p>
           </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {statCards.map((stat) => (
          <div key={stat.name} className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-lg shadow-slate-200/20 hover:scale-[1.02] transition-transform duration-300 relative overflow-hidden group">
            <div className={`absolute top-0 right-0 w-32 h-32 ${stat.bg} rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 opacity-50 group-hover:opacity-100 transition-opacity`} />
            <div className="flex justify-between items-start mb-6 relative z-10">
              <div className={`w-14 h-14 ${stat.bg} ${stat.color} rounded-2xl flex items-center justify-center border border-current/10 shadow-inner`}>
                <stat.icon size={28} />
              </div>
              <div className="flex items-center gap-1 text-[10px] font-black text-emerald-500 uppercase tracking-tighter bg-emerald-50 px-2 py-1 rounded-lg">
                 <TrendingUp size={12} />
                 {stat.trend}
              </div>
            </div>
            <p className="text-slate-400 font-bold uppercase tracking-[0.2em] text-xs mb-1 relative z-10">{stat.name}</p>
            <h2 className="text-5xl font-black text-academic-navy tracking-tighter relative z-10">{stat.value}</h2>
          </div>
        ))}
      </div>

      {/* Main Content Split */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Recent Inquiries */}
        <div className="bg-white rounded-[2rem] border border-slate-100 shadow-lg p-8">
           <div className="flex items-center justify-between mb-8 pb-4 border-b border-slate-100">
              <h3 className="text-xl font-black text-academic-navy tracking-tight">Recent Inquiries</h3>
              <Link href="/admin/admissions" className="text-xs font-bold text-blue-600 hover:text-blue-700 hover:underline flex items-center gap-1 bg-blue-50 px-3 py-1.5 rounded-full transition-colors">
                 View All <ArrowUpRight size={14} />
              </Link>
           </div>
           
           <div className="space-y-4">
              {recentInquiries.length > 0 ? recentInquiries.map((inq, i) => {
                const date = new Date(inq.created_at);
                const isToday = date.toDateString() === new Date().toDateString();
                const timeStr = isToday ? date.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : date.toLocaleDateString();

                return (
                 <div key={inq.id} className="flex items-center gap-4 p-4 rounded-2xl hover:bg-slate-50 transition-colors border border-transparent hover:border-slate-100 group">
                    <div className="w-12 h-12 rounded-full bg-blue-50 flex items-center justify-center text-blue-600 font-black group-hover:bg-blue-600 group-hover:text-white transition-colors shadow-sm">
                       {inq.name ? inq.name.charAt(0).toUpperCase() : '?'}
                    </div>
                    <div className="flex-1 min-w-0">
                       <p className="font-black text-academic-navy leading-tight truncate">{inq.name || 'Unknown'}</p>
                       <p className="text-xs text-slate-500 font-medium truncate">{inq.course || 'Not specified'}</p>
                    </div>
                    <div className="text-right">
                       <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{timeStr}</p>
                       <div className="w-2 h-2 bg-blue-500 rounded-full ml-auto mt-1 shadow-sm shadow-blue-500/50" />
                    </div>
                 </div>
              )}) : (
                <div className="text-center py-10">
                  <GraduationCap className="mx-auto text-slate-300 mb-3" size={40} />
                  <p className="text-slate-500 font-bold">No recent inquiries found.</p>
                </div>
              )}
           </div>
        </div>

        {/* Quick Actions */}
        <div className="bg-[#0A0F1C] rounded-[2rem] p-8 text-white relative overflow-hidden shadow-xl border border-white/5">
           <div className="absolute inset-0 bg-gradient-to-br from-blue-600/20 to-purple-600/20 mix-blend-overlay" />
           <h3 className="text-xl font-black mb-8 relative z-10">Quick Actions</h3>
           <div className="grid grid-cols-2 gap-4 relative z-10">
              <Link href="/admin/notices" className="p-6 bg-white/5 border border-white/10 rounded-2xl hover:bg-white/10 hover:border-white/20 transition-all group backdrop-blur-sm active:opacity-80 active:translate-y-[1px]">
                 <Bell className="mb-4 text-blue-400 group-hover:scale-110 transition-transform drop-shadow-md" size={28} />
                 <p className="font-bold text-sm tracking-wide">Post Notice</p>
              </Link>
              <Link href="/admin/faculty" className="p-6 bg-white/5 border border-white/10 rounded-2xl hover:bg-white/10 hover:border-white/20 transition-all group backdrop-blur-sm active:opacity-80 active:translate-y-[1px]">
                 <Users className="mb-4 text-purple-400 group-hover:scale-110 transition-transform drop-shadow-md" size={28} />
                 <p className="font-bold text-sm tracking-wide">Manage Staff</p>
              </Link>
              <Link href="/" target="_blank" className="p-6 bg-white/5 border border-white/10 rounded-2xl hover:bg-white/10 hover:border-white/20 transition-all group backdrop-blur-sm active:opacity-80 active:translate-y-[1px]">
                 <Globe className="mb-4 text-emerald-400 group-hover:scale-110 transition-transform drop-shadow-md" size={28} />
                 <p className="font-bold text-sm tracking-wide">Live Website</p>
              </Link>
              <Link href="/admin/videos" className="p-6 bg-white/5 border border-white/10 rounded-2xl hover:bg-white/10 hover:border-white/20 transition-all group backdrop-blur-sm active:opacity-80 active:translate-y-[1px]">
                 <Clock className="mb-4 text-amber-400 group-hover:scale-110 transition-transform drop-shadow-md" size={28} />
                 <p className="font-bold text-sm tracking-wide">Add Video</p>
              </Link>
           </div>
           
           {/* Decorative Background Icon */}
           <ShieldCheck className="absolute -bottom-10 -right-10 w-64 h-64 text-white/5 rotate-12 pointer-events-none" />
        </div>
      </div>
    </div>
  );
}

"use client";
 
import React, { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { 
  Users, 
  Plus, 
  Trash2, 
  Edit2, 
  Mail, 
  GraduationCap, 
  UserPlus, 
  Loader2, 
  Camera,
  X,
  Save,
  Briefcase
} from 'lucide-react';
import Image from 'next/image';
import ImageCropper from '@/components/ImageCropper';
 
interface Faculty {
  id: string;
  name: string;
  designation: string;
  department: string;
  qualification: string;
  email: string;
  experience: string;
  image_url?: string;
}
 
export default function FacultyManager() {
  const [faculty, setFaculty] = useState<Faculty[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingFaculty, setEditingFaculty] = useState<Partial<Faculty> | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [uploadingImage, setUploadingImage] = useState(false);
 
  const fetchFaculty = React.useCallback(async () => {
    setIsLoading(true);
    const { data, error } = await supabase
      .from('faculty')
      .select('*')
      .order('id', { ascending: true });

    const getRank = (designation: string = '') => {
      const d = designation.toLowerCase();
      if (d.includes('principal')) return 1;
      if (d.includes('founder')) return 2;
      if (d.includes('head of') || d.includes('hod')) return 3;
      if (d.includes('senior')) return 4;
      if (d.includes('faculty')) return 5;
      return 6;
    };

    if (!error && data) {
      const sortedData = [...data].sort((a, b) => getRank(a.designation) - getRank(b.designation));
      setFaculty(sortedData);
    }
    setIsLoading(false);
  }, []);
 
  useEffect(() => {
    const timer = setTimeout(() => {
      fetchFaculty();
    }, 0);
    return () => clearTimeout(timer);
  }, [fetchFaculty]);
 
  const handleOpenModal = (item?: Faculty) => {
    setEditingFaculty(item || {
      name: '',
      designation: '',
      department: 'Science',
      qualification: '',
      email: '',
      experience: '',
      image_url: ''
    });
    setIsModalOpen(true);
  };
 
  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingFaculty(null);
  };
 
  const [tempImageUrl, setTempImageUrl] = useState<string | null>(null);
  const [showCropper, setShowCropper] = useState(false);
 
  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    
    const reader = new FileReader();
    reader.onload = () => {
      setTempImageUrl(reader.result as string);
      setShowCropper(true);
    };
    reader.readAsDataURL(file);
  };

  const handleCropComplete = async (croppedBlob: Blob) => {
    setShowCropper(false);
    setUploadingImage(true);
    try {
      const fileName = `faculty-${Date.now()}.jpg`;
      const filePath = `faculty/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, croppedBlob, {
          contentType: 'image/jpeg'
        });

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('images')
        .getPublicUrl(filePath);

      setEditingFaculty(prev => prev ? { ...prev, image_url: publicUrl } : null);
    } catch (error) {
      const err = error as { message: string };
      alert('Error uploading cropped image: ' + err.message);
    } finally {
      setUploadingImage(false);
      setTempImageUrl(null);
    }
  };
 
  const handleSave = async () => {
    if (!editingFaculty?.name || !editingFaculty?.email) {
      alert('Name and Email are required');
      return;
    }
 
    setIsSaving(true);
    try {
      if (editingFaculty.id) {
        // Update
        const { error } = await supabase
          .from('faculty')
          .update(editingFaculty)
          .eq('id', editingFaculty.id);
        if (error) throw error;
      } else {
        // Insert
        const { error } = await supabase
          .from('faculty')
          .insert([editingFaculty]);
        if (error) throw error;
      }
      
      await fetchFaculty();
      handleCloseModal();
    } catch (error) {
      const err = error as { message: string };
      alert('Error saving faculty: ' + err.message);
    } finally {
      setIsSaving(false);
    }
  };
 
  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to remove this faculty member?')) return;
 
    try {
      const { error } = await supabase
        .from('faculty')
        .delete()
        .eq('id', id);
      if (error) throw error;
      await fetchFaculty();
    } catch (error) {
      const err = error as { message: string };
      alert('Error deleting: ' + err.message);
    }
  };
 
  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="animate-spin text-academic-navy" size={40} />
      </div>
    );
  }
 
  return (
    <div className="space-y-8 pb-20">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-black text-academic-navy tracking-tight">Faculty Management</h1>
          <p className="text-slate-500 font-medium">Add, edit, or remove teaching staff records.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="flex items-center gap-2 px-6 py-3 bg-academic-navy text-white font-black rounded-xl hover:bg-slate-800 transition-all shadow-xl hover:shadow-academic-navy/20 active:opacity-80 active:translate-y-[1px]"
        >
          <UserPlus size={20} />
          Add Faculty
        </button>
      </div>
 
      {/* Table View */}
      <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
                <th className="px-6 py-5 text-[11px] font-black text-slate-400 uppercase tracking-widest">Faculty Member</th>
                <th className="px-6 py-5 text-[11px] font-black text-slate-400 uppercase tracking-widest">Department</th>
                <th className="px-6 py-5 text-[11px] font-black text-slate-400 uppercase tracking-widest">Experience</th>
                <th className="px-6 py-5 text-[11px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {faculty.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-6 py-12 text-center text-slate-400 font-medium">
                    No faculty records found. Start by adding one.
                  </td>
                </tr>
              ) : faculty.map((f) => (
                <tr key={f.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-4">
                       <div className="w-12 h-12 rounded-xl bg-slate-100 overflow-hidden relative border border-slate-200 shadow-sm">
                          {f.image_url ? (
                            <Image src={f.image_url} alt={f.name} fill className="object-cover" />
                          ) : (
                            <div className="w-full h-full flex items-center justify-center bg-slate-100">
                              <Users size={24} className="text-slate-300" />
                            </div>
                          )}
                       </div>
                       <div>
                          <p className="font-black text-academic-navy">{f.name}</p>
                          <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">{f.designation}</p>
                       </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-xs font-bold">
                       {f.department}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                     <div className="flex items-center gap-2 text-sm font-medium text-slate-500">
                        <Briefcase size={14} className="text-academic-gold" />
                        {f.experience}
                     </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={() => handleOpenModal(f)}
                        className="p-2.5 text-slate-400 hover:text-academic-navy transition-all hover:bg-slate-100 rounded-xl"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => handleDelete(f.id)}
                        className="p-2.5 text-slate-400 hover:text-red-500 transition-all hover:bg-red-50 rounded-xl"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
 
      {/* Edit/Add Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-academic-navy/40 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-2xl rounded-[2rem] shadow-2xl overflow-hidden animate-in slide-in-from-bottom-8 duration-500">
              {/* Modal Header */}
              <div className="bg-academic-navy p-8 text-white flex justify-between items-center">
                 <div>
                    <h2 className="text-2xl font-black tracking-tight">{editingFaculty?.id ? 'Edit Profile' : 'New Faculty Member'}</h2>
                    <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">Personnel Information System</p>
                 </div>
                 <button onClick={handleCloseModal} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                    <X size={24} />
                 </button>
              </div>
 
              <div className="p-8 max-h-[70vh] overflow-y-auto">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    {/* Profile Image Section */}
                    <div className="md:col-span-2 flex flex-col items-center justify-center py-6 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200">
                       <div className="relative w-32 h-32 rounded-3xl overflow-hidden border-4 border-white shadow-xl mb-4 group/img">
                          {editingFaculty?.image_url ? (
                             <Image src={editingFaculty.image_url} alt="Preview" fill className="object-cover" />
                          ) : (
                             <div className="w-full h-full bg-slate-100 flex items-center justify-center">
                                <Users size={48} className="text-slate-300" />
                             </div>
                          )}
