"use client";
 
import React, { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { 
  Bell, 
  Plus, 
  Trash2, 
  Calendar, 
  FileText, 
  Loader2, 
  Edit2, 
  X, 
  Save, 
  Pin,
  Megaphone,
  Upload,
  Image as ImageIcon,
  ExternalLink
} from 'lucide-react';
 
interface Notice {
  id: string;
  title: string;
  date: string;
  category: string;
  content: string;
  is_pinned: boolean;
  pdf_url?: string;
  image_url?: string;
}
 
export default function NoticeManager() {
  const [notices, setNotices] = useState<Notice[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingNotice, setEditingNotice] = useState<Partial<Notice> | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [isUploading, setIsUploading] = useState<'pdf' | 'image' | null>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: 'pdf' | 'image') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(type);
    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).slice(2)}.${fileExt}`;
      const bucket = type === 'pdf' ? 'notices' : 'images';
      const filePath = `notices/${fileName}`;
      const { error: uploadError } = await supabase.storage.from(bucket).upload(filePath, file);
      if (uploadError) throw uploadError;
      const { data: { publicUrl } } = supabase.storage.from(bucket).getPublicUrl(filePath);
      setEditingNotice(prev => prev ? { ...prev, [type === 'pdf' ? 'pdf_url' : 'image_url']: publicUrl } : null);
    } catch (error: unknown) {
      const err = error as Error;
      alert(`Error uploading ${type}: ` + err.message);
    } finally {
      setIsUploading(null);
    }
  };
 
  const fetchNotices = React.useCallback(async () => {
    const { data, error } = await supabase
      .from('notices')
      .select('*')
      .order('is_pinned', { ascending: false })
      .order('date', { ascending: false });
    
    if (!error && data) {
      setNotices(data);
    }
    setIsLoading(false);
  }, []);

  useEffect(() => {
    let isMounted = true;
    if (isMounted) {
      fetchNotices();
    }
    return () => { isMounted = false; };
  }, [fetchNotices]);
 
  const handleOpenModal = (item?: Notice) => {
    setEditingNotice(item || {
      title: '',
      category: 'General',
      content: '',
      date: new Date().toISOString().split('T')[0],
      is_pinned: false
    });
    setIsModalOpen(true);
  };
 
  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingNotice(null);
  };
 
  const handleSave = async () => {
    if (!editingNotice?.title || !editingNotice?.content) {
      alert('Heading and Text content are required');
      return;
    }
 
    setIsSaving(true);
    try {
      const payload = {
        title: editingNotice.title,
        content: editingNotice.content,
        category: editingNotice.category,
        date: editingNotice.date,
        is_pinned: !!editingNotice.is_pinned,
        pdf_url: editingNotice.pdf_url,
        image_url: editingNotice.image_url
      };

      if (editingNotice.id) {
        // Update
        const { error } = await supabase
          .from('notices')
          .update(payload)
          .eq('id', editingNotice.id);
        if (error) throw error;
      } else {
        // Insert
        const { error } = await supabase
          .from('notices')
          .insert([payload]);
        if (error) throw error;
      }
      
      await fetchNotices();
      handleCloseModal();
    } catch (error: unknown) {
      const err = error as Error;
      alert('Error saving notice: ' + err.message);
    } finally {
      setIsSaving(false);
    }
  };
 
  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this notice?')) return;
 
    try {
      const { error } = await supabase
        .from('notices')
        .delete()
        .eq('id', id);
      if (error) throw error;
      await fetchNotices();
    } catch (error: unknown) {
      const err = error as { message: string };
      alert('Error deleting: ' + err.message);
    }
  };
 
  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="animate-spin text-academic-navy" size={40} />
      </div>
    );
  }
 
  return (
    <div className="space-y-8 pb-20">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-black text-academic-navy tracking-tight">Notice Board Manager</h1>
          <p className="text-slate-500 font-medium">Publish official announcements and updates.</p>
        </div>
        {!isModalOpen && (
          <button 
            onClick={() => handleOpenModal()}
            className="flex items-center justify-center gap-2 px-6 py-3 bg-academic-navy text-white font-black rounded-xl hover:bg-slate-800 transition-all shadow-xl hover:shadow-academic-navy/20 active:opacity-80 active:translate-y-[1px]"
          >
            <Megaphone size={20} />
            New Announcement
          </button>
        )}
      </div>
 
      {!isModalOpen ? (
        /* Notices List */
        <div className="grid grid-cols-1 gap-4">
          {notices.length === 0 ? (
            <div className="bg-white p-12 text-center rounded-3xl border border-slate-100 text-slate-400">
               No active notices. Create your first announcement above.
            </div>
          ) : notices.map((notice) => (
            <div key={notice.id} className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col md:flex-row items-start md:items-center gap-6 group hover:shadow-md transition-all">
               <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 ${notice.is_pinned ? 'bg-academic-gold text-academic-navy' : 'bg-slate-50 text-slate-400'}`}>
                  {notice.is_pinned ? <Pin size={24} /> : <Bell size={24} />}
               </div>
               <div className="flex-1 min-w-0 w-full">
                  <div className="flex items-center gap-3 mb-2">
                     <span className="text-[10px] font-black uppercase tracking-widest px-2.5 py-1 bg-slate-100 text-slate-500 rounded-lg">
                        {notice.category}
                     </span>
                     <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-400">
                        <Calendar size={12} />
                        {new Date(notice.date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })}
                     </div>
                  </div>
                  <h3 className="font-black text-academic-navy text-lg leading-tight mb-2 truncate">{notice.title}</h3>
                  <p className="text-sm text-slate-500 line-clamp-1">{notice.content}</p>
               </div>
               <div className="flex gap-2 w-full md:w-auto mt-4 md:mt-0 justify-end">
                  <button 
                    onClick={() => handleOpenModal(notice)}
                    className="p-3 text-slate-400 hover:text-academic-navy hover:bg-slate-50 rounded-xl transition-all"
                  >
                     <Edit2 size={20} />
                  </button>
                  <button 
                    onClick={() => handleDelete(notice.id)}
                    className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                  >
                     <Trash2 size={20} />
                  </button>
               </div>
            </div>
          ))}
        </div>
      ) : (
        /* Inline Editor */
        <div className="bg-white w-full rounded-[2.5rem] shadow-xl overflow-hidden border border-slate-100">
          <div className="bg-academic-navy p-6 md:p-8 text-white flex justify-between items-center">
             <div className="flex items-center gap-4">
                <div className="w-12 h-12 rounded-xl bg-academic-gold/20 border border-academic-gold/30 flex items-center justify-center text-academic-gold">
                   <Megaphone size={24} />
                </div>
                <div>
                   <h2 className="text-xl md:text-2xl font-black tracking-tight">{editingNotice?.id ? 'Update Notice' : 'New Notice'}</h2>
                   <p className="text-slate-400 text-[10px] md:text-xs font-bold uppercase tracking-widest mt-1">Official Bulletin System</p>
                </div>
             </div>
             <button onClick={handleCloseModal} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                <X size={24} />
             </button>
          </div>

          <div className="p-6 md:p-8 space-y-6">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Notice Heading</label>
                   <input 
                      type="text" 
                      value={editingNotice?.title || ''}
                      onChange={e => setEditingNotice(p => ({...p!, title: e.target.value}))}
                      className="w-full px-5 py-4 rounded-2xl border border-slate-200 focus:border-academic-gold focus:ring-4 focus:ring-academic-gold/10 outline-none transition-all font-bold text-academic-navy" 
                      placeholder="e.g. Semester Exam Fee Last Date" 
                   />
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Category</label>
                   <select 
                      value={editingNotice?.category || 'General'}
                      onChange={e => setEditingNotice(p => ({...p!, category: e.target.value}))}
                      className="w-full px-5 py-4 rounded-2xl border border-slate-200 focus:border-academic-gold outline-none font-bold text-slate-600 appearance-none bg-no-repeat bg-[right_1.25rem_center] bg-[length:1em_1em]"
                   >
                      <option>General</option>
                      <option>Exam</option>
                      <option>Admission</option>
                      <option>Holiday</option>
                      <option>Event</option>
                   </select>
                </div>
             </div>

             <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Notice Content (Text)</label>
                <textarea 
                   rows={6}
                   value={editingNotice?.content || ''}
                   onChange={e => setEditingNotice(p => ({...p!, content: e.target.value}))}
                   className="w-full px-5 py-4 rounded-2xl border border-slate-200 focus:border-academic-gold focus:ring-4 focus:ring-academic-gold/10 outline-none transition-all font-medium resize-y" 
                   placeholder="Detailed information about the announcement..."
                />
             </div>

             {/* File Uploads */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100 flex flex-col items-center justify-center text-center gap-2">
                    <ImageIcon className="text-slate-400" size={24} />
                    <label className="cursor-pointer">
                       <span className="text-[10px] font-black text-academic-navy uppercase tracking-widest hover:text-academic-gold transition-colors">
                          {isUploading === 'image' ? 'Uploading...' : editingNotice?.image_url ? 'Change Image' : 'Upload Image'}
                       </span>
                       <input type="file" className="hidden" accept="image/*" onChange={e => handleFileUpload(e, 'image')} disabled={!!isUploading} />
                    </label>
                    {editingNotice?.image_url && <span className="text-[8px] text-green-600 font-bold uppercase tracking-widest">Attached</span>}
                 </div>
                 <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100 flex flex-col items-center justify-center text-center gap-2">
                    <FileText className="text-slate-400" size={24} />
                    <label className="cursor-pointer">
                       <span className="text-[10px] font-black text-academic-navy uppercase tracking-widest hover:text-academic-gold transition-colors">
                          {isUploading === 'pdf' ? 'Uploading...' : editingNotice?.pdf_url ? 'Change PDF' : 'Upload PDF'}
                       </span>
                       <input type="file" className="hidden" accept=".pdf" onChange={e => handleFileUpload(e, 'pdf')} disabled={!!isUploading} />
                    </label>
                    {editingNotice?.pdf_url && <span className="text-[8px] text-green-600 font-bold uppercase tracking-widest">Attached</span>}
                 </div>
              </div>

               <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <input 
                     type="checkbox" 
                     id="is_pinned"
                     checked={editingNotice?.is_pinned || false}
                     onChange={e => setEditingNotice(p => ({...p!, is_pinned: e.target.checked}))}
                     className="w-5 h-5 rounded border-slate-300 text-academic-navy focus:ring-academic-navy cursor-pointer" 
                  />
                  <label htmlFor="is_pinned" className="text-sm font-bold text-slate-600 cursor-pointer">Pin this notice to the top</label>
               </div>
          </div>

          <div className="p-6 md:p-8 bg-slate-50 flex flex-col md:flex-row gap-4">
             <button 
                onClick={handleSave}
                disabled={isSaving}
                className="flex-1 py-4 bg-academic-navy text-white font-black rounded-2xl hover:bg-slate-800 transition-all flex items-center justify-center gap-2 shadow-xl shadow-academic-navy/20 disabled:opacity-50"
             >
                {isSaving ? <Loader2 className="animate-spin" size={20} /> : <Save size={20} />}
                {editingNotice?.id ? 'Publish Changes' : 'Post Announcement'}
             </button>
             <button 
                onClick={handleCloseModal}
                className="px-8 py-4 bg-white text-slate-500 font-black rounded-2xl border border-slate-200 hover:bg-slate-50 transition-all"
             >
                Discard
             </button>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";
 
import React, { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { 
  Image as ImageIcon, 
  Plus, 
  Trash2, 
  Maximize2, 
  Loader2, 
  UploadCloud, 
  X, 
  Camera, 
  Save,
  Grid,
  Calendar
} from 'lucide-react';
import Image from 'next/image';
 
interface GalleryImage {
  id: string;
  url: string;
  caption: string;
  category: string;
}
 
export default function GalleryManager() {
  const [images, setImages] = useState<GalleryImage[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isAdding, setIsAdding] = useState(false);
  const [newImage, setNewImage] = useState<Partial<GalleryImage>>({ caption: '', category: 'Video', url: '' });
  const [isSaving, setIsSaving] = useState(false);
 
  const fetchImages = React.useCallback(async () => {
    const { data, error } = await supabase
      .from('gallery')
      .select('*')
      .order('created_at', { ascending: false });
    
    if (!error && data) {
      setImages(data.filter((img: GalleryImage) => img.url.includes('youtube.com') || img.url.includes('youtu.be')));
    }
    setIsLoading(false);
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => {
      fetchImages();
    }, 0);
    return () => clearTimeout(timer);
  }, [fetchImages]);
 
  const handleSave = async () => {
    if (!newImage.url || !newImage.caption) {
      alert('Video URL and Caption are required');
      return;
    }
 
    setIsSaving(true);
    try {
      const { error } = await supabase
        .from('gallery')
        .insert([{ ...newImage, category: 'Video' }]);
      
      if (error) throw error;
      
      await fetchImages();
      setIsAdding(false);
      setNewImage({ caption: '', category: 'Video', url: '' });
    } catch (error: unknown) {
      const err = error as { message: string };
      alert('Error saving to gallery: ' + err.message);
    } finally {
      setIsSaving(false);
    }
  };
 
  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to remove this video from the gallery?')) return;
 
    try {
      await supabase.from('gallery').delete().eq('id', id);
      await fetchImages();
    } catch (error: unknown) {
      const err = error as { message: string };
      alert('Error deleting: ' + err.message);
    }
  };
 
  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="animate-spin text-academic-navy" size={40} />
      </div>
    );
  }
 
  return (
    <div className="space-y-8 pb-20 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-black text-academic-navy tracking-tight">Video Gallery Manager</h1>
          <p className="text-slate-500 font-medium">Curate YouTube videos for S.K. Degree College.</p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="flex items-center gap-2 px-6 py-3 bg-academic-navy text-white font-black rounded-xl hover:bg-slate-800 transition-all shadow-xl active:opacity-80 active:translate-y-[1px]"
        >
          <Camera size={20} />
          Add YouTube Video
        </button>
      </div>
 
      {isAdding && (
         <div className="bg-white p-8 rounded-[2rem] shadow-2xl border border-slate-100 animate-in fade-in slide-in-from-top-4 duration-300">
            <div className="flex items-center justify-between mb-8">
               <h2 className="text-xl font-black text-academic-navy flex items-center gap-3">
                  <UploadCloud className="text-blue-500" />
                  Add YouTube Link
               </h2>
               <button onClick={() => setIsAdding(false)} className="p-2 hover:bg-slate-50 rounded-full transition-all">
                  <X size={20} className="text-slate-400" />
               </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
               {/* Media Area */}
               <div className="relative aspect-video bg-slate-50 rounded-[2rem] border-4 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-400 overflow-hidden group/upload">
                    {newImage.url && (newImage.url.includes('youtube.com') || newImage.url.includes('youtu.be')) ? (
                      <>
                        <Image 
                          src={`https://img.youtube.com/vi/${(() => {
                            const match = newImage.url.match(/^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/);
                            return match && match[2].length === 11 ? match[2] : '';
                          })()}/hqdefault.jpg`} 
                          alt="Video Preview"
                          fill
                          unoptimized
                          className="w-full h-full object-cover" 
                        />
                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                          <div className="w-16 h-16 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center border-2 border-white/50">
                            <div className="w-0 h-0 border-t-8 border-t-transparent border-l-[14px] border-l-white border-b-8 border-b-transparent ml-1" />
                          </div>
                        </div>
                      </>
                    ) : (
                      <div className="text-center p-6">
                        <Camera size={48} className="mx-auto mb-2 opacity-20 text-blue-500" />
                        <p className="text-xs font-black uppercase tracking-widest text-slate-500">
                          Video Preview
                        </p>
                      </div>
                    )}
               </div>
 
               <div className="space-y-6">
                    <div className="space-y-2">
                       <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">YouTube Video URL</label>
                       <input 
                          type="url" 
                          value={newImage.url || ''}
                          onChange={(e) => setNewImage({...newImage, url: e.target.value})}
                          className="w-full px-5 py-4 rounded-2xl border border-slate-200 focus:border-blue-500 outline-none font-bold text-academic-navy transition-all" 
                          placeholder="https://www.youtube.com/watch?v=..." 
                       />
                    </div>
                  <div className="space-y-2">
                     <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Video Title</label>
                     <input 
                        type="text" 
                        value={newImage.caption}
                        onChange={(e) => setNewImage({...newImage, caption: e.target.value})}
                        className="w-full px-5 py-4 rounded-2xl border border-slate-200 focus:border-blue-500 outline-none font-bold text-academic-navy transition-all" 
                        placeholder="e.g. Annual Day Celebrations" 
                     />
                  </div>
                  <div className="pt-4 flex gap-4">
                     <button 
                        onClick={handleSave}
                        disabled={isSaving || !newImage.url || !newImage.caption}
                        className="flex-1 py-4 bg-academic-navy text-white font-black rounded-2xl hover:bg-slate-800 transition-all active:opacity-80 active:translate-y-[1px] flex items-center justify-center gap-2 shadow-xl shadow-academic-navy/20 disabled:opacity-50"
                     >
                        {isSaving ? <Loader2 className="animate-spin" size={20} /> : <Save size={20} />}
                        Save Video
                     </button>
                  </div>
               </div>
            </div>
         </div>
      )}
 
      {/* Gallery Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {images.length === 0 ? (
          <div className="col-span-full bg-white p-20 text-center rounded-[3rem] border border-slate-100 text-slate-400">
             <Grid size={48} className="mx-auto mb-4 opacity-10" />
             <p className="font-bold text-lg">Your gallery is empty.</p>
             <p className="text-sm">Start building your visual library by uploading photos.</p>
          </div>
        ) : images.map((img) => (
          <div key={img.id} className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden group hover:shadow-2xl transition-all duration-500">
            <div className="aspect-[4/3] relative overflow-hidden">
               {img.url.includes('youtube.com') || img.url.includes('youtu.be') ? (
                 <Image 
                   src={`https://img.youtube.com/vi/${(() => {
                     const match = img.url.match(/^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/);
                     return match && match[2].length === 11 ? match[2] : '';
                   })()}/hqdefault.jpg`} 
                   alt={img.caption}
                   fill
                   unoptimized
                   className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" 
                 />
               ) : (
                 <Image src={img.url} alt={img.caption} fill className="object-cover group-hover:scale-110 transition-transform duration-700" />
               )}
               {(img.url.includes('youtube.com') || img.url.includes('youtu.be')) && (
                 <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                   <div className="w-12 h-12 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center border-2 border-white/50">
                     <div className="w-0 h-0 border-t-[6px] border-t-transparent border-l-[10px] border-l-white border-b-[6px] border-b-transparent ml-1" />
                   </div>
                 </div>
               )}
               <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-3">
                  <button 
                    onClick={() => handleDelete(img.id)}
                    className="p-4 bg-red-500 text-white rounded-2xl shadow-xl hover:scale-110 active:scale-90 transition-all"
                    title="Delete Photo"
                  >
                     <Trash2 size={24} />
                  </button>
                  <button 
                    className="p-4 bg-white text-academic-navy rounded-2xl shadow-xl hover:scale-110 active:scale-90 transition-all"
                    title="View Fullscreen"
                  >
                     <Maximize2 size={24} />
                  </button>
               </div>
               <div className="absolute top-6 left-6">
                  <span className="px-4 py-1.5 bg-white/90 backdrop-blur-md text-academic-navy text-[10px] font-black uppercase tracking-widest rounded-full shadow-lg">
                     {img.category}
                  </span>
               </div>
            </div>
            <div className="p-8">
               <h3 className="font-black text-academic-navy text-lg leading-tight mb-2 truncate">{img.caption}</h3>
               <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                  <Calendar size={12} className="text-academic-gold" />
                  Media Asset #{img.id.slice(-4)}
               </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import FacultyCard from '@/components/FacultyCard';
import MotionSection, { StaggerContainer, StaggerItem, TextReveal } from '@/components/motion/MotionSection';
import ParticleCanvas from '@/components/ParticleCanvas';
import initialFacultyData from '@/lib/data/faculty.json';
import { Faculty } from '@/lib/types';
import { supabase } from '@/lib/supabase';
import { Users, Filter, Sparkles, Loader2 } from 'lucide-react';
import Image from 'next/image';

export default function FacultyPage() {
  const [faculty, setFaculty] = useState<Faculty[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedDept, setSelectedDept] = useState('All Departments');

  useEffect(() => {
    fetchFaculty();
  }, []);

  async function fetchFaculty() {
    setLoading(true);
    const { data, error } = await supabase
      .from('faculty')
      .select('*')
      .order('id', { ascending: true });

    const getRank = (designation: string = '') => {
      const d = designation.toLowerCase();
      if (d.includes('principal')) return 1;
      if (d.includes('founder')) return 2;
      if (d.includes('head of') || d.includes('hod')) return 3;
      if (d.includes('senior')) return 4;
      if (d.includes('faculty')) return 5;
      return 6;
    };

    if (!error && data && data.length > 0) {
      const sortedData = [...data].sort((a, b) => getRank(a.designation) - getRank(b.designation));
      setFaculty(sortedData);
    } else {
      const sortedInitial = [...(initialFacultyData as Faculty[])].sort((a, b) => getRank(a.designation) - getRank(b.designation));
      setFaculty(sortedInitial);
    }
    setLoading(false);
  }

  const departments = [
    'All Departments',
    'Administration',
    ...new Set(faculty
      .map(m => m.department)
      .filter(d => d !== 'Administration' && d !== 'All Departments')
      .sort()
    )
  ];

  const filteredFaculty = selectedDept === 'All Departments'
    ? faculty
    : faculty.filter(m => {
      if (selectedDept === 'Administration') {
        return m.designation?.toLowerCase().includes('principal') ||
          m.designation?.toLowerCase().includes('founder of the society') ||
          //  m.designation?.toLowerCase().includes('hod') ||
          m.designation?.toLowerCase().includes('head of department') ||
          m.department === 'Administration';
      }
      return m.department === selectedDept;
    });

  return (
    <main className="min-h-screen bg-slate-50 pb-20">
      {/* Hero Section with 3D Particle Background */}
      <section className="relative bg-academic-navy pt-32 pb-24 overflow-hidden">
        <ParticleCanvas className="opacity-60" />

        <div className="container mx-auto px-4 relative z-10">
          <div className="flex flex-col md:flex-row items-end justify-between gap-8">
            <div className="max-w-2xl">
              <MotionSection delay={0.1}>
                <div className="flex items-center gap-2 text-academic-gold font-bold uppercase tracking-widest mb-4">
