                  <Tag className="text-academic-gold" size={20} />
                  Recent Stories
                </h3>

                <div className="space-y-6">
                  {recentNews.map((item) => (
                    <Link key={item.id} href={`/news/${item.id}`} className="flex gap-4 group">
                      <div className="relative w-16 h-16 shrink-0 rounded-xl overflow-hidden">
                        <Image 
